ControlflowRule.Definition:
state start START;
			state READ;
			state error BADACCESS;
			state END;

			var rv;
			var buf;

			pattern ifOk { #ifblock(rv, null, false) }

			START -> READ { rv = fgets(buf, ...) }
			READ -> END { pattern ifOk }
			READ -> END { buf = ? }
			READ -> END { strcpy(buf, ?) | sprintf(buf, ...) }
			READ -> BADACCESS { strcpy(?, buf) | printf(..., buf, ...) | sprintf(?, ..., buf, ...) }

state start(start);
			state read;
			state write;
			state err(error);
			var  file;

			pattern read { $freadFirst(file, ...) | $freadLast(..., file) }
			pattern write { $fwriteFirst(file, ...) | $fwriteLast(..., file) }

			start -> read { pattern read }
			write -> err { pattern read }

			read -> start { $fflush(..., file, ...) }
			write -> start { $fflush(..., file, ...) }

			start -> write { pattern write }
			read -> write { pattern write }

state s(start);
			state value;
			state checked;
			state err(error);

			var rv;

			s -> value { rv = returnVal(...) }
			value -> checked { #compare(rv, -1) }
			value -> checked { #compare(rv, 0) }
			value -> checked { #compare(rv, null) }
			value -> err { rv = ? }
			value -> err { #end_scope(rv) }
			value -> err { rv }

state start s;
			state goodval;
			state error err;

			var f;

			s ->goodval { fgetpos(?,  f) }
			s -> err { fsetpos(?, f) }

state start START;
			state DEC;
			state error FREE;

			var str;

			START -> DEC { #buffer_declaration(str) }
			DEC -> FREE { $free( str ) }

state start START;
state GET;
state error MOD;

var str;

START -> GET{ str = $getenv(...) }
GET -> MOD{ *str = ? }

state start START;
			state GET;
			state EOFCHK;
			state ERRCHK;
			state error EOF;

			var c;

			START -> GET{ c = $get(...) }
			GET -> EOFCHK{ $feof(...) }
			EOFCHK -> ERRCHK{ $ferror(...) }
			GET -> ERRCHK{ $ferror(...) }
			ERRCHK -> EOFCHK{ $feof(...) }
			GET -> EOF{ #end_function() }

state start START;
			state OPEN;
			state CLOSE;
			state error SYS;

			var f;

			START -> OPEN{ f = $fopen(...) }
			OPEN -> CLOSE{ $fclose(f) }
			OPEN -> SYS{ $system(...) }

state start START;
			state FN;
			state OPEN;
			state CLOSE;
			state END;
			state error AGAIN;

			var f;
			var file;

			START -> OPEN{ f=$fopen(file,...) }
			OPEN -> CLOSE{ $fclose(f) }
			CLOSE -> END{ #end_scope(f) }
			CLOSE -> AGAIN{ f=$fopen(file,...) }

		 state start START;
                 state VAR;
                 state CHK;
                 state CALL;
                 state error NCHK;

                 var x;

                 pattern fns{$acos(x)|$asin(x)|$atan2(x,...)|$atan2(...,x)|$log(x)|$log10(x)|$pow(x,...)|$pow(...,x)|$sqrt(x)}

		 START -> VAR{ #any_declaration(x) | #param(x, ?) | x = ?}
		 VAR -> CHK{ #compare(x, ?) |isless(x,?) |isgreater(x,?) }
		 CHK -> CALL{pattern fns | $sqrt(x)}
		 VAR -> NCHK{ pattern fns | $sqrt(x) }

state start START;
			state TRUNC;
			state GOOD;
			state OKIF;
			state error ERROR;
			state error END;

			var str1;
			var str2;

			START -> TRUNC{$stringfn(str1, ..., str2)}
			TRUNC -> OKIF{#ifblock(str2, ?, false)}
			TRUNC -> ERROR{str1}
			TRUNC -> END{#end_function()}

			START -> OKIF{#ifblock(str2, ?, false)}
			OKIF -> GOOD{$stringfn(str1, ..., str2)}

state start START;
			state MALLOC;
			state FREE;
			state error BADFREE;
			state error END;

			var foo;

			START -> MALLOC{foo = $malloc(...)}
			START -> BADFREE{$free(foo)}
			MALLOC -> FREE{$free(foo)}
			MALLOC -> END{#end_function()}

state start START;
			state error MAKE;
			state error OPEN;
			state GOODMAKE;

			var foo;
			var bar;

			pattern makefilename{ $tmpnam(bar,...) | $mktemp(bar) }
			pattern openfile{ foo = $fopen(bar,...) | $open(bar,...) | $tmpfile(...) }
			pattern makegood{ $mkstemp(...) | $tmpfile_s(...) }

			START -> MAKE{ pattern makefilename }
			START -> OPEN{ pattern openfile }
			MAKE -> OPEN{ pattern openfile }
			START -> GOODMAKE{ pattern makegood }

state start START;
			state LOCK;
			state UNLOCK;
			state DESTROY;
			state error BADDESTROY;

			var foo;

			START -> LOCK{ $lock(foo) }
			LOCK -> DESTROY{ $destroy(foo) }
			LOCK -> UNLOCK{ $unlock(foo) }
			START -> BADDESTROY{ $destroy(foo) }
